  <script>
    (function(){
      const toggle = document.querySelector('.menu-toggle');
      const navrow = document.querySelector('#mobileNav');
      if(toggle && navrow){
        toggle.addEventListener('click', function(){
          const isOpen = navrow.classList.toggle('open');
          toggle.setAttribute('aria-expanded', String(isOpen));
        });
      }
      document.querySelectorAll('.faq-q').forEach(function(btn){
        btn.addEventListener('click', function(){
          const item = btn.closest('.faq-item');
          const open = item.classList.contains('open');
          document.querySelectorAll('.faq-item').forEach(function(i){ i.classList.remove('open'); });
          if(!open){ item.classList.add('open'); }
        });
      });

      const slider = document.querySelector('#promoSlider');
      if(slider){
        const slides = Array.from(slider.querySelectorAll('.promo-slide'));
        const dots = Array.from(slider.querySelectorAll('.promo-dot'));
        const prev = slider.querySelector('.promo-prev');
        const next = slider.querySelector('.promo-next');
        let current = 0;
        let timer = null;
        function showSlide(index){
          current = (index + slides.length) % slides.length;
          slides.forEach(function(slide, i){ slide.classList.toggle('active', i === current); });
          dots.forEach(function(dot, i){ dot.classList.toggle('active', i === current); });
        }
        function goNext(){ showSlide(current + 1); }
        function goPrev(){ showSlide(current - 1); }
        function restart(){
          if(timer){ clearInterval(timer); }
          if(slides.length > 1){ timer = setInterval(goNext, 6000); }
        }
        if(next){ next.addEventListener('click', function(){ goNext(); restart(); }); }
        if(prev){ prev.addEventListener('click', function(){ goPrev(); restart(); }); }
        dots.forEach(function(dot, index){ dot.addEventListener('click', function(){ showSlide(index); restart(); }); });
        restart();
      }
    })();
  </script>
